const BASE = process.env.REACT_APP_API_URL || 'http://localhost:4000/api';

function getToken() {
  return localStorage.getItem('linkargo_token');
}

async function request(path, options = {}) {
  const token = getToken();
  const headers = {
    'Content-Type': 'application/json',
    ...(token ? { Authorization: `Bearer ${token}` } : {}),
    ...options.headers,
  };

  const res = await fetch(`${BASE}${path}`, { ...options, headers });
  const data = await res.json();

  if (!res.ok) {
    throw new Error(data.error || data.message || 'Something went wrong');
  }
  return data;
}

// ── Auth ─────────────────────────────────────
export const auth = {
  register: (body) => request('/auth/register', { method: 'POST', body: JSON.stringify(body) }),
  login: (body) => request('/auth/login', { method: 'POST', body: JSON.stringify(body) }),
  me: () => request('/auth/me'),
};

// ── Jobs ─────────────────────────────────────
export const jobs = {
  create: (body) => request('/jobs', { method: 'POST', body: JSON.stringify(body) }),
  list: (params = {}) => {
    const q = new URLSearchParams(params).toString();
    return request(`/jobs${q ? '?' + q : ''}`);
  },
  get: (id) => request(`/jobs/${id}`),
  myJobs: () => request('/jobs/my'),
  cancel: (id) => request(`/jobs/${id}/cancel`, { method: 'PATCH' }),
};

// ── Quotes ───────────────────────────────────
export const quotes = {
  submit: (jobId, body) => request(`/jobs/${jobId}/quotes`, { method: 'POST', body: JSON.stringify(body) }),
  listForJob: (jobId) => request(`/jobs/${jobId}/quotes`),
  accept: (quoteId) => request(`/quotes/${quoteId}/accept`, { method: 'PATCH' }),
  reject: (quoteId) => request(`/quotes/${quoteId}/reject`, { method: 'PATCH' }),
  myQuotes: () => request('/quotes/my'),
};

// ── Profiles ─────────────────────────────────
export const profiles = {
  get: (userId) => request(`/profiles/${userId}`),
  update: (body) => request('/profiles/me', { method: 'PUT', body: JSON.stringify(body) }),
  getCarrierProfile: () => request('/profiles/carrier'),
};

// ── Messages ─────────────────────────────────
export const messages = {
  getThread: (jobId) => request(`/messages/${jobId}`),
  send: (jobId, text) => request(`/messages/${jobId}`, { method: 'POST', body: JSON.stringify({ text }) }),
};

// ── Stats ─────────────────────────────────────
export const stats = {
  carrier: () => request('/stats/carrier'),
  shipper: () => request('/stats/shipper'),
};
